const usage = $input.first().json;
const ONE_GB = 1024 * 1024 * 1024;

const thresholds = {
  storage: 30 * ONE_GB,
  bandwidth: 30 * ONE_GB,
  videoUnits: 1,
  aiUnits: 1,
  originalCache: 1
};

function progressBar(value, max, blocks = 20) {
  const pct = value / max;
  const filled = Math.min(Math.round(pct * blocks), blocks);
  const empty = blocks - filled;
  return '`' + '█'.repeat(filled) + '▒'.repeat(empty) + '`' + ` ${(pct * 100).toFixed(1)}%`;
}

const checks = [
  { metric: 'Storage',                value: usage.mediaLibraryStorageBytes,  max: thresholds.storage,       display: (v) => (v / ONE_GB).toFixed(2) + ' GB', threshold: '30 GB' },
  { metric: 'Bandwidth',              value: usage.bandwidthBytes,             max: thresholds.bandwidth,     display: (v) => (v / ONE_GB).toFixed(2) + ' GB', threshold: '30 GB' },
  { metric: 'Video Units',            value: usage.videoProcessingUnitsCount,  max: thresholds.videoUnits,    display: (v) => v,                               threshold: '5000'  },
  { metric: 'Extension Units',        value: usage.extensionUnitsCount,        max: thresholds.aiUnits,       display: (v) => v,                               threshold: '5000'  },
  { metric: 'Original Cache Storage', value: usage.originalCacheStorageBytes,  max: thresholds.originalCache, display: (v) => v,                               threshold: '1000'  },
];

const breaches = checks
  .filter(c => c.value >= c.max)
  .map(c => ({
    metric: c.metric,
    value: c.display(c.value),
    threshold: c.threshold,
    bar: progressBar(c.value, c.max)
  }));

if (breaches.length === 0) return [];

return [{ json: { breaches } }];

